import { Test, TestingModule } from '@nestjs/testing';
import { RoundsService } from './rounds.service';
import { PrismaService } from '../prisma/prisma.service';
import { AuditLogService } from '../audit-log/audit-log.service';

describe('RoundsService', () => {
  let service: RoundsService;
  let prisma: PrismaService;
  let auditLog: AuditLogService;

  // Mock data
  const mockUserId = 'user-123';
  const mockPlayerId = 'player-456';
  const mockRoundId = 'round-789';

  const mockPlayer = {
    id: mockPlayerId,
    userId: mockUserId,
    firstName: 'John',
    lastName: 'Doe',
    ghinNumber: '1234567',
    handicap: 15.2,
    createdAt: new Date(),
    updatedAt: new Date(),
  };

  const mockRound = {
    id: mockRoundId,
    playerId: mockPlayerId,
    courseName: 'Pebble Beach Golf Links',
    strokes: 72,
    date: new Date('2025-10-15'),
    notes: 'Great day!',
    createdAt: new Date(),
    updatedAt: new Date(),
    deletedAt: null,
  };

  const mockPrismaService = {
    player: {
      findUnique: jest.fn(),
    },
    round: {
      findMany: jest.fn(),
      findFirst: jest.fn(),
      create: jest.fn(),
      update: jest.fn(),
    },
  };

  const mockAuditLogService = {
    log: jest.fn(),
  };

  beforeEach(async () => {
    const module: TestingModule = await Test.createTestingModule({
      providers: [
        RoundsService,
        {
          provide: PrismaService,
          useValue: mockPrismaService,
        },
        {
          provide: AuditLogService,
          useValue: mockAuditLogService,
        },
      ],
    }).compile();

    service = module.get<RoundsService>(RoundsService);
    prisma = module.get<PrismaService>(PrismaService);
    auditLog = module.get<AuditLogService>(AuditLogService);

    // Reset mocks before each test
    jest.clearAllMocks();
  });

  it('should be defined', () => {
    expect(service).toBeDefined();
  });

  describe('listByUser', () => {
    it('should return empty array if player not found', async () => {
      mockPrismaService.player.findUnique.mockResolvedValue(null);

      const result = await service.listByUser(mockUserId);

      expect(result).toEqual([]);
      expect(mockPrismaService.player.findUnique).toHaveBeenCalledWith({
        where: { userId: mockUserId },
      });
    });

    it('should return rounds for valid player', async () => {
      mockPrismaService.player.findUnique.mockResolvedValue(mockPlayer);
      mockPrismaService.round.findMany.mockResolvedValue([mockRound]);

      const result = await service.listByUser(mockUserId);

      expect(result).toEqual([mockRound]);
      expect(mockPrismaService.round.findMany).toHaveBeenCalledWith({
        where: {
          playerId: mockPlayerId,
          deletedAt: null,
        },
        orderBy: { date: 'desc' },
        take: 20,
      });
      expect(mockAuditLogService.log).toHaveBeenCalled();
    });

    it('should filter by search term (case-insensitive)', async () => {
      mockPrismaService.player.findUnique.mockResolvedValue(mockPlayer);
      mockPrismaService.round.findMany.mockResolvedValue([mockRound]);

      await service.listByUser(mockUserId, { search: 'pebble' });

      expect(mockPrismaService.round.findMany).toHaveBeenCalledWith({
        where: {
          playerId: mockPlayerId,
          deletedAt: null,
          courseName: {
            contains: 'pebble',
            mode: 'insensitive',
          },
        },
        orderBy: { date: 'desc' },
        take: 20,
      });
    });

    it('should sort by strokes ascending', async () => {
      mockPrismaService.player.findUnique.mockResolvedValue(mockPlayer);
      mockPrismaService.round.findMany.mockResolvedValue([mockRound]);

      await service.listByUser(mockUserId, {
        sortBy: 'strokes',
        sortOrder: 'asc',
      });

      expect(mockPrismaService.round.findMany).toHaveBeenCalledWith({
        where: {
          playerId: mockPlayerId,
          deletedAt: null,
        },
        orderBy: { strokes: 'asc' },
        take: 20,
      });
    });

    it('should respect limit parameter (max 100)', async () => {
      mockPrismaService.player.findUnique.mockResolvedValue(mockPlayer);
      mockPrismaService.round.findMany.mockResolvedValue([mockRound]);

      await service.listByUser(mockUserId, { limit: 50 });

      expect(mockPrismaService.round.findMany).toHaveBeenCalledWith(
        expect.objectContaining({ take: 50 })
      );

      // Test max limit enforcement
      await service.listByUser(mockUserId, { limit: 200 });
      expect(mockPrismaService.round.findMany).toHaveBeenLastCalledWith(
        expect.objectContaining({ take: 100 })
      );
    });

    it('should exclude soft-deleted rounds', async () => {
      mockPrismaService.player.findUnique.mockResolvedValue(mockPlayer);
      mockPrismaService.round.findMany.mockResolvedValue([]);

      await service.listByUser(mockUserId);

      expect(mockPrismaService.round.findMany).toHaveBeenCalledWith(
        expect.objectContaining({
          where: expect.objectContaining({ deletedAt: null }),
        })
      );
    });
  });

  describe('createForUser', () => {
    const createData = {
      courseName: 'Augusta National',
      strokes: 68,
      date: '2025-10-20',
      notes: 'Amazing round',
    };

    it('should throw error if player not found', async () => {
      mockPrismaService.player.findUnique.mockResolvedValue(null);

      await expect(service.createForUser(mockUserId, createData)).rejects.toThrow(
        'No player profile for user'
      );
    });

    it('should create round with valid data', async () => {
      mockPrismaService.player.findUnique.mockResolvedValue(mockPlayer);
      mockPrismaService.round.create.mockResolvedValue(mockRound);

      const result = await service.createForUser(mockUserId, createData);

      expect(result).toEqual(mockRound);
      expect(mockPrismaService.round.create).toHaveBeenCalledWith({
        data: {
          playerId: mockPlayerId,
          courseName: createData.courseName,
          strokes: createData.strokes,
          notes: createData.notes,
          date: new Date(createData.date),
        },
      });
      expect(mockAuditLogService.log).toHaveBeenCalled();
    });

    it('should create round without optional fields', async () => {
      mockPrismaService.player.findUnique.mockResolvedValue(mockPlayer);
      mockPrismaService.round.create.mockResolvedValue(mockRound);

      const minimalData = {
        courseName: 'Augusta National',
        strokes: 68,
      };

      await service.createForUser(mockUserId, minimalData);

      expect(mockPrismaService.round.create).toHaveBeenCalledWith({
        data: {
          playerId: mockPlayerId,
          courseName: minimalData.courseName,
          strokes: minimalData.strokes,
        },
      });
    });

    it('should log audit entry on successful creation', async () => {
      mockPrismaService.player.findUnique.mockResolvedValue(mockPlayer);
      mockPrismaService.round.create.mockResolvedValue(mockRound);

      await service.createForUser(mockUserId, createData);

      expect(mockAuditLogService.log).toHaveBeenCalledWith(
        mockUserId,
        expect.any(String), // AuditAction.ROUND_CREATED
        `Round:${mockRoundId}`,
        expect.objectContaining({
          courseName: createData.courseName,
          strokes: createData.strokes,
        })
      );
    });
  });

  describe('updateRound', () => {
    const updateData = {
      courseName: 'Updated Course',
      strokes: 70,
      date: '2025-10-21',
      notes: 'Updated notes',
    };

    it('should throw error if player not found', async () => {
      mockPrismaService.player.findUnique.mockResolvedValue(null);

      await expect(
        service.updateRound(mockUserId, mockRoundId, updateData)
      ).rejects.toThrow('No player profile for user');
    });

    it('should throw error if round not found', async () => {
      mockPrismaService.player.findUnique.mockResolvedValue(mockPlayer);
      mockPrismaService.round.findFirst.mockResolvedValue(null);

      await expect(
        service.updateRound(mockUserId, mockRoundId, updateData)
      ).rejects.toThrow('Round not found');
    });

    it('should throw error if round belongs to different user', async () => {
      mockPrismaService.player.findUnique.mockResolvedValue(mockPlayer);
