      mockPrismaService.round.findFirst.mockResolvedValue(null); // findFirst filters deletedAt: null

      await expect(service.softDeleteRound(mockUserId, mockRoundId)).rejects.toThrow(
        'Round not found or already deleted'
      );
    });
  });
});

