    {
      id: 'round-1',
      playerId: mockPlayerId,
      courseName: 'Pebble Beach',
      strokes: 72,
      date: new Date('2025-10-15'),
      notes: null,
      createdAt: new Date(),
      updatedAt: new Date(),
      deletedAt: null,
    },
    {
      id: 'round-2',
      playerId: mockPlayerId,
      courseName: 'Augusta National',
      strokes: 68,
      date: new Date('2025-10-10'),
      notes: null,
      createdAt: new Date(),
      updatedAt: new Date(),
      deletedAt: null,
    },
    {
      id: 'round-3',
      playerId: mockPlayerId,
      courseName: 'Pebble Beach',
      strokes: 75,
      date: new Date('2025-10-05'),
      notes: null,
      createdAt: new Date(),
      updatedAt: new Date(),
      deletedAt: null,
    },
  ];

  const mockPrismaService = {
    user: {
      findUnique: jest.fn(),
      update: jest.fn(),
      delete: jest.fn(),
    },
    player: {
      findUnique: jest.fn(),
      upsert: jest.fn(),
      delete: jest.fn(),
    },
    round: {
      deleteMany: jest.fn(),
    },
    auditLog: {
      deleteMany: jest.fn(),
    },
    $transaction: jest.fn(),
  };

  const mockAuditLogService = {
    log: jest.fn(),
  };

  beforeEach(async () => {
    const module: TestingModule = await Test.createTestingModule({
      providers: [
        ProfileService,
        {
          provide: PrismaService,
          useValue: mockPrismaService,
        },
        {
          provide: AuditLogService,
          useValue: mockAuditLogService,
        },
      ],
    }).compile();

    service = module.get<ProfileService>(ProfileService);
    prisma = module.get<PrismaService>(PrismaService);
    auditLog = module.get<AuditLogService>(AuditLogService);

    jest.clearAllMocks();
  });

  it('should be defined', () => {
    expect(service).toBeDefined();
  });

  describe('getMe', () => {
    it('should return user with player profile', async () => {
      mockPrismaService.user.findUnique.mockResolvedValue(mockUser);

      const result = await service.getMe(mockUserId);

      expect(result).toEqual(mockUser);
      expect(mockPrismaService.user.findUnique).toHaveBeenCalledWith({
        where: { id: mockUserId },
        select: expect.any(Object),
      });
      expect(mockAuditLogService.log).toHaveBeenCalled();
    });

    it('should throw NotFoundException if user not found', async () => {
      mockPrismaService.user.findUnique.mockResolvedValue(null);

      await expect(service.getMe(mockUserId)).rejects.toThrow(NotFoundException);
      await expect(service.getMe(mockUserId)).rejects.toThrow('User not found');
    });
  });

  describe('updateMe', () => {
    it('should update user and player fields', async () => {
      const updateData = {
        firstName: 'Jane',
        lastName: 'Smith',
        ghinNumber: '7654321',
        handicap: 12.5,
      };

      const updatedUser = {
        ...mockUser,
        ...updateData,
        player: { ...mockUser.player, ...updateData },
      };

      mockPrismaService.$transaction.mockImplementation(async (callback) => {
        return callback({
          user: {
            findUnique: jest.fn()
              .mockResolvedValueOnce(mockUser) // First call to check if user exists
              .mockResolvedValueOnce(updatedUser), // Second call to return updated user
            update: jest.fn().mockResolvedValue(updatedUser),
          },
          player: {
            upsert: jest.fn().mockResolvedValue({
              ...mockUser.player,
              ...updateData,
            }),
          },
        });
      });

      const result = await service.updateMe(mockUserId, updateData);

      expect(result.firstName).toBe(updateData.firstName);
      expect(mockAuditLogService.log).toHaveBeenCalled();
    });

    it('should throw NotFoundException if user not found', async () => {
      mockPrismaService.$transaction.mockImplementation(async (callback) => {
        return callback({
          user: {
            findUnique: jest.fn().mockResolvedValue(null),
          },
        });
      });

      await expect(
        service.updateMe(mockUserId, { firstName: 'Test' })
      ).rejects.toThrow(NotFoundException);
    });

    it('should trim whitespace from string inputs', async () => {
      let capturedData: any = {};

      mockPrismaService.$transaction.mockImplementation(async (callback) => {
        return callback({
          user: {
            findUnique: jest.fn().mockResolvedValue(mockUser),
            update: jest.fn((args) => {
              capturedData.user = args.data;
              return Promise.resolve({ ...mockUser });
            }),
          },
          player: {
            upsert: jest.fn((args) => {
              capturedData.player = args.update;
              return Promise.resolve({ ...mockUser.player });
            }),
          },
        });
      });

      mockPrismaService.user.findUnique.mockResolvedValue(mockUser);

      await service.updateMe(mockUserId, {
        firstName: '  Trimmed  ',
        ghinNumber: '  12345  ',
      });

      // Verify trimming happened (captured in the mock calls)
      expect(mockPrismaService.$transaction).toHaveBeenCalled();
    });

    it('should handle null handicap', async () => {
      const updatedUserWithNullHandicap = {
        ...mockUser,
        player: { ...mockUser.player, handicap: null },
      };

      mockPrismaService.$transaction.mockImplementation(async (callback) => {
        return callback({
          user: {
            findUnique: jest.fn()
              .mockResolvedValueOnce(mockUser)
              .mockResolvedValueOnce(updatedUserWithNullHandicap),
            update: jest.fn().mockResolvedValue(mockUser),
          },
          player: {
            upsert: jest.fn().mockResolvedValue({
              ...mockUser.player,
              handicap: null,
            }),
          },
        });
      });

      const result = await service.updateMe(mockUserId, { handicap: null });

      expect(result.player?.handicap).toBeNull();
    });

    it('should convert empty ghinNumber to null', async () => {
      const updatedUserWithNullGhin = {
        ...mockUser,
        player: { ...mockUser.player, ghinNumber: null },
      };

      mockPrismaService.$transaction.mockImplementation(async (callback) => {
        return callback({
          user: {
            findUnique: jest.fn()
              .mockResolvedValueOnce(mockUser)
              .mockResolvedValueOnce(updatedUserWithNullGhin),
            update: jest.fn().mockResolvedValue(mockUser),
          },
          player: {
            upsert: jest.fn().mockResolvedValue({
              ...mockUser.player,
              ghinNumber: null,
            }),
          },
        });
      });

      const result = await service.updateMe(mockUserId, { ghinNumber: '' });

      // Empty string should result in null ghinNumber in the result
      expect(result.player?.ghinNumber).toBeNull();
    });
  });

  describe('getStats', () => {
    it('should return empty stats if player not found', async () => {
      mockPrismaService.player.findUnique.mockResolvedValue(null);

      const result = await service.getStats(mockUserId);

      expect(result).toEqual({
        totalRounds: 0,
        averageScore: null,
        bestScore: null,
        worstScore: null,
        recentRounds: [],
        coursesPlayed: [],
      });
    });

    it('should return empty stats if no rounds', async () => {
      mockPrismaService.player.findUnique.mockResolvedValue({
        ...mockUser.player,
        rounds: [],
      });

      const result = await service.getStats(mockUserId);

      expect(result).toEqual({
        totalRounds: 0,
        averageScore: null,
        bestScore: null,
        worstScore: null,
        recentRounds: [],
        coursesPlayed: [],
      });
    });

    it('should calculate correct statistics from rounds', async () => {
      mockPrismaService.player.findUnique.mockResolvedValue({
        ...mockUser.player,
        rounds: mockRounds,
      });

      const result = await service.getStats(mockUserId);

      expect(result.totalRounds).toBe(3);
      expect(result.averageScore).toBe(72); // (72 + 68 + 75) / 3 = 71.67, rounded to 72
      expect(result.bestScore).toBe(68);
      expect(result.worstScore).toBe(75);
      expect(result.recentRounds).toHaveLength(3);
    });

    it('should return top 5 recent rounds', async () => {
      const manyRounds = Array.from({ length: 10 }, (_, i) => ({
        ...mockRounds[0],
        id: `round-${i}`,
        date: new Date(2025, 9, 20 - i), // Descending dates
      }));

      mockPrismaService.player.findUnique.mockResolvedValue({
        ...mockUser.player,
        rounds: manyRounds,
      });

      const result = await service.getStats(mockUserId);

      expect(result.recentRounds).toHaveLength(5);
      expect(result.recentRounds[0].id).toBe('round-0'); // Most recent
    });

    it('should count courses played correctly', async () => {
      mockPrismaService.player.findUnique.mockResolvedValue({
        ...mockUser.player,
        rounds: mockRounds, // 2x Pebble Beach, 1x Augusta
      });

      const result = await service.getStats(mockUserId);

      expect(result.coursesPlayed).toHaveLength(2);
      expect(result.coursesPlayed[0]).toEqual({
        name: 'Pebble Beach',
        count: 2,
      });
      expect(result.coursesPlayed[1]).toEqual({
        name: 'Augusta National',
        count: 1,
      });
    });

    it('should return top 5 courses by play count', async () => {
      const manyCourseRounds = [
        ...Array(10).fill({ ...mockRounds[0], courseName: 'Course A' }),
        ...Array(8).fill({ ...mockRounds[0], courseName: 'Course B' }),
        ...Array(6).fill({ ...mockRounds[0], courseName: 'Course C' }),
        ...Array(4).fill({ ...mockRounds[0], courseName: 'Course D' }),
        ...Array(2).fill({ ...mockRounds[0], courseName: 'Course E' }),
        ...Array(1).fill({ ...mockRounds[0], courseName: 'Course F' }),
      ].map((round, i) => ({ ...round, id: `round-${i}` }));

      mockPrismaService.player.findUnique.mockResolvedValue({
        ...mockUser.player,
        rounds: manyCourseRounds,
      });

      const result = await service.getStats(mockUserId);

      expect(result.coursesPlayed).toHaveLength(5); // Top 5 only
      expect(result.coursesPlayed[0].name).toBe('Course A');
      expect(result.coursesPlayed[0].count).toBe(10);
      expect(result.coursesPlayed[4].name).toBe('Course E');
      // Course F (count: 1) should not be in top 5
    });

    it('should exclude soft-deleted rounds from stats', async () => {
      mockPrismaService.player.findUnique.mockResolvedValue({
        ...mockUser.player,
        rounds: mockRounds,
      });

      await service.getStats(mockUserId);

      expect(mockPrismaService.player.findUnique).toHaveBeenCalledWith({
        where: { userId: mockUserId },
        include: {
          rounds: {
            where: { deletedAt: null },
            orderBy: { date: 'desc' },
          },
        },
      });
    });
  });

  describe('exportUserData', () => {
    it('should export user data with all relationships', async () => {
      mockPrismaService.user.findUnique.mockResolvedValue({
        ...mockUser,
        avatarUrl: 'https://example.com/avatar.jpg',
        locale: 'en-US',
        emailVerified: true,
        lastLoginAt: new Date('2025-10-20'),
        provider: 'google',
        providerId: 'google-123',
        hostedDomain: null,
        player: {
          ...mockUser.player,
          rounds: mockRounds,
        },
      });

      const result = await service.exportUserData(mockUserId);

      expect(result.user.email).toBe(mockUser.email);
      expect(result.player).toBeDefined();
      expect(result.rounds).toHaveLength(3);
      expect(result.exportedAt).toBeDefined();
      expect(mockAuditLogService.log).toHaveBeenCalled();
    });

    it('should throw NotFoundException if user not found', async () => {
      mockPrismaService.user.findUnique.mockResolvedValue(null);

      await expect(service.exportUserData(mockUserId)).rejects.toThrow(
        NotFoundException
      );
    });

    it('should exclude deleted rounds from export', async () => {
      mockPrismaService.user.findUnique.mockResolvedValue({
        ...mockUser,
        player: {
          ...mockUser.player,
          rounds: mockRounds,
        },
      });

      await service.exportUserData(mockUserId);

      expect(mockPrismaService.user.findUnique).toHaveBeenCalledWith({
        where: { id: mockUserId },
        include: {
          player: {
            include: {
              rounds: {
                where: { deletedAt: null },
                orderBy: { date: 'desc' },
              },
            },
          },
        },
      });
    });
  });

  describe('deleteUserAccount', () => {
    it('should delete user and all associated data', async () => {
      mockPrismaService.user.findUnique.mockResolvedValue({
        ...mockUser,
        player: mockUser.player,
      });

      mockPrismaService.$transaction.mockImplementation(async (callback) => {
        return callback({
          round: {
            deleteMany: jest.fn().mockResolvedValue({ count: 3 }),
          },
          player: {
            delete: jest.fn().mockResolvedValue(mockUser.player),
          },
          auditLog: {
            deleteMany: jest.fn().mockResolvedValue({ count: 10 }),
          },
          user: {
            delete: jest.fn().mockResolvedValue(mockUser),
          },
        });
      });

      const result = await service.deleteUserAccount(mockUserId);

      expect(result.deleted).toBe(true);
      expect(result.userId).toBe(mockUserId);
      expect(mockAuditLogService.log).toHaveBeenCalled();
    });

    it('should throw NotFoundException if user not found', async () => {
      mockPrismaService.user.findUnique.mockResolvedValue(null);

      await expect(service.deleteUserAccount(mockUserId)).rejects.toThrow(
        NotFoundException
      );
    });

    it('should handle user without player gracefully', async () => {
      mockPrismaService.user.findUnique.mockResolvedValue({
        ...mockUser,
        player: null,
      });

      mockPrismaService.$transaction.mockImplementation(async (callback) => {
        return callback({
          auditLog: {
            deleteMany: jest.fn().mockResolvedValue({ count: 5 }),
          },
          user: {
            delete: jest.fn().mockResolvedValue(mockUser),
          },
        });
      });

      const result = await service.deleteUserAccount(mockUserId);

      expect(result.deleted).toBe(true);
    });
  });
});

'use client';

import { useEffect, useState } from 'react';
import Link from 'next/link';
import Image from 'next/image';
import { Button } from '@/components/ui/button';
import { getSession, getGoogleLoginUrl } from '@/lib/auth';

export default function LoginPage() {
  const [isChecking, setIsChecking] = useState(true);
  const [isAuthenticated, setIsAuthenticated] = useState(false);

  useEffect(() => {
    // Check if user is already logged in
    getSession()
      .then((session) => {
        if (session.authenticated) {
          setIsAuthenticated(true);
          // Redirect to profile after a brief moment
          setTimeout(() => {
            window.location.href = '/profile';
          }, 1500);
        }
      })
      .catch(() => {
        // Ignore errors, show login
      })
      .finally(() => {
        setIsChecking(false);
      });
  }, []);

  return (
    <div className="relative w-full overflow-hidden">
      {/* Background effects */}
      <div className="absolute inset-0 -z-10 bg-glow-mixed" />

      <div className="w-full max-w-md mx-auto px-4 py-16">
        <div className="glass rounded-2xl p-8 text-center space-y-8">
          {/* Logo */}
          <div className="flex justify-center">
            <Image
              src="/images/logo.png"
              alt="Lazy Golfing"
              width={200}
              height={148}
              className="h-24 w-auto"
            />
          </div>

          {/* Title */}
          <div className="space-y-2">
            <h1 className="text-2xl font-bold">Welcome Back</h1>
            <p className="text-muted-foreground">
              Sign in to track your rounds and improve your game
            </p>
          </div>

          {/* Status */}
          {isChecking ? (
            <div className="py-4">
              <div className="animate-pulse text-muted-foreground">
                Checking session...
              </div>
            </div>
          ) : isAuthenticated ? (
            <div className="py-4 space-y-2">
              <div className="text-brand-pink font-semibold">
                You&apos;re already logged in!
              </div>
              <div className="text-muted-foreground text-sm">
                Redirecting to your profile...
              </div>
            </div>
          ) : (
            <>
              {/* Google Sign In Button */}
              <Button
                size="lg"
                className="w-full text-base gap-3"
                onClick={() => {
                  window.location.href = getGoogleLoginUrl();
                }}
              >
                <svg className="w-5 h-5" viewBox="0 0 24 24">
                  <path
                    fill="currentColor"
                    d="M22.56 12.25c0-.78-.07-1.53-.2-2.25H12v4.26h5.92c-.26 1.37-1.04 2.53-2.21 3.31v2.77h3.57c2.08-1.92 3.28-4.74 3.28-8.09z"
                  />
                  <path
                    fill="currentColor"
                    d="M12 23c2.97 0 5.46-.98 7.28-2.66l-3.57-2.77c-.98.66-2.23 1.06-3.71 1.06-2.86 0-5.29-1.93-6.16-4.53H2.18v2.84C3.99 20.53 7.7 23 12 23z"
                  />
                  <path
                    fill="currentColor"
                    d="M5.84 14.09c-.22-.66-.35-1.36-.35-2.09s.13-1.43.35-2.09V7.07H2.18C1.43 8.55 1 10.22 1 12s.43 3.45 1.18 4.93l2.85-2.22.81-.62z"
                  />
                  <path
                    fill="currentColor"
                    d="M12 5.38c1.62 0 3.06.56 4.21 1.64l3.15-3.15C17.45 2.09 14.97 1 12 1 7.7 1 3.99 3.47 2.18 7.07l3.66 2.84c.87-2.6 3.3-4.53 6.16-4.53z"
                  />
                </svg>
                Sign in with Google
              </Button>

              {/* Tagline */}
              <p className="text-sm gradient-text-golden italic">
                Cart golf only!
              </p>
            </>
          )}

          {/* Back to home */}
          <div className="pt-4 border-t border-border/50">
            <Link
              href="/"
              className="text-sm text-muted-foreground hover:text-foreground transition-colors"
            >
              &larr; Back to home
            </Link>
          </div>
        </div>
      </div>
    </div>
  );
}

