'use client';

/**
 * Confirmation dialog component for destructive actions.
 * Uses shadcn/ui AlertDialog with Miami Vice theme styling.
 */

import { useState } from 'react';
import {
  AlertDialog,
  AlertDialogAction,
  AlertDialogCancel,
  AlertDialogContent,
  AlertDialogDescription,
  AlertDialogFooter,
  AlertDialogHeader,
  AlertDialogTitle,
  AlertDialogTrigger,
} from '@/components/ui/alert-dialog';
import { Button } from '@/components/ui/button';
import { Spinner } from '@/components/loading';
import { cn } from '@/lib/utils';

interface ConfirmDialogProps {
  trigger: React.ReactNode;
  title: string;
  description: string;
  confirmText?: string;
  cancelText?: string;
  variant?: 'default' | 'destructive';
  onConfirm: () => Promise<void> | void;
  onCancel?: () => void;
}

/**
 * Reusable confirmation dialog for destructive actions
 *
 * @example
 * <ConfirmDialog
 *   trigger={<Button variant="destructive">Delete</Button>}
 *   title="Delete Round"
 *   description="Are you sure you want to delete this round? This action cannot be undone."
 *   confirmText="Delete"
 *   variant="destructive"
 *   onConfirm={handleDelete}
 * />
 */
export function ConfirmDialog({
  trigger,
  title,
  description,
  confirmText = 'Confirm',
  cancelText = 'Cancel',
  variant = 'default',
  onConfirm,
  onCancel,
}: ConfirmDialogProps) {
  const [open, setOpen] = useState(false);
  const [isLoading, setIsLoading] = useState(false);

  const handleConfirm = async () => {
    setIsLoading(true);
    try {
      await onConfirm();
      setOpen(false);
    } catch (error) {
      // Error handling should be done in onConfirm
      console.error('Confirm action failed:', error);
    } finally {
      setIsLoading(false);
    }
  };

  const handleCancel = () => {
    onCancel?.();
    setOpen(false);
  };

  return (
    <AlertDialog open={open} onOpenChange={setOpen}>
      <AlertDialogTrigger asChild>{trigger}</AlertDialogTrigger>
      <AlertDialogContent className="glass">
        <AlertDialogHeader>
          <AlertDialogTitle>{title}</AlertDialogTitle>
          <AlertDialogDescription>{description}</AlertDialogDescription>
        </AlertDialogHeader>
        <AlertDialogFooter>
          <AlertDialogCancel onClick={handleCancel} disabled={isLoading}>
            {cancelText}
          </AlertDialogCancel>
          <AlertDialogAction
            onClick={(e) => {
              e.preventDefault();
              handleConfirm();
            }}
            disabled={isLoading}
            className={cn(
              variant === 'destructive' &&
                'bg-destructive text-destructive-foreground hover:bg-destructive/90'
            )}
          >
            {isLoading ? (
              <>
                <Spinner className="mr-2" />
                Processing...
              </>
            ) : (
              confirmText
            )}
          </AlertDialogAction>
        </AlertDialogFooter>
      </AlertDialogContent>
    </AlertDialog>
  );
}

/**
 * Pre-configured delete confirmation dialog
 */
export function DeleteConfirmDialog({
  itemName,
  onConfirm,
  trigger,
}: {
  itemName: string;
  onConfirm: () => Promise<void> | void;
  trigger?: React.ReactNode;
}) {
  return (
    <ConfirmDialog
      trigger={
        trigger || (
          <Button variant="destructive" size="sm">
            Delete
          </Button>
        )
      }
      title={`Delete ${itemName}?`}
      description={`Are you sure you want to delete this ${itemName.toLowerCase()}? This action cannot be undone.`}
      confirmText="Delete"
      variant="destructive"
      onConfirm={onConfirm}
    />
  );
}

/**
 * Pre-configured unsaved changes confirmation dialog
 */
export function UnsavedChangesDialog({
  onConfirm,
  onCancel,
  trigger,
}: {
  onConfirm: () => Promise<void> | void;
  onCancel?: () => void;
  trigger: React.ReactNode;
}) {
  return (
    <ConfirmDialog
      trigger={trigger}
      title="Unsaved Changes"
      description="You have unsaved changes. Are you sure you want to leave? Your changes will be lost."
      confirmText="Leave"
      cancelText="Stay"
      variant="destructive"
      onConfirm={onConfirm}
      onCancel={onCancel}
    />
  );
}

