/**
 * Toast notification utilities for consistent messaging across the app.
 * Wraps sonner toast with pre-configured options.
 */

import { toast as sonnerToast } from 'sonner';

/**
 * Show a success toast notification
 */
export function toastSuccess(message: string, description?: string) {
  sonnerToast.success(message, {
    description,
    duration: 4000,
  });
}

/**
 * Show an error toast notification
 */
export function toastError(message: string, description?: string) {
  sonnerToast.error(message, {
    description,
    duration: 6000,
  });
}

/**
 * Show an info toast notification
 */
export function toastInfo(message: string, description?: string) {
  sonnerToast.info(message, {
    description,
    duration: 4000,
  });
}

/**
 * Show a warning toast notification
 */
export function toastWarning(message: string, description?: string) {
  sonnerToast.warning(message, {
    description,
    duration: 5000,
  });
}

/**
 * Show a loading toast that can be updated
 * Returns a function to dismiss the toast
 */
export function toastLoading(message: string) {
  const id = sonnerToast.loading(message);
  return {
    dismiss: () => sonnerToast.dismiss(id),
    success: (newMessage: string) =>
      sonnerToast.success(newMessage, { id, duration: 3000 }),
    error: (newMessage: string) =>
      sonnerToast.error(newMessage, { id, duration: 5000 }),
  };
}

/**
 * Show a promise-based toast that updates based on promise state
 */
export function toastPromise<T>(
  promise: Promise<T>,
  messages: {
    loading: string;
    success: string;
    error: string;
  }
) {
  return sonnerToast.promise(promise, {
    loading: messages.loading,
    success: messages.success,
    error: messages.error,
  });
}

/**
 * Pre-built toast patterns for common actions
 */
export const toast = {
  success: toastSuccess,
  error: toastError,
  info: toastInfo,
  warning: toastWarning,
  loading: toastLoading,
  promise: toastPromise,

  // Common patterns
  saved: () => toastSuccess('Changes saved'),
  deleted: (item = 'Item') => toastSuccess(`${item} deleted`),
  created: (item = 'Item') => toastSuccess(`${item} created`),
  updated: (item = 'Item') => toastSuccess(`${item} updated`),
  copied: () => toastSuccess('Copied to clipboard'),

  // Error patterns
  saveFailed: () => toastError('Failed to save changes', 'Please try again'),
  deleteFailed: () => toastError('Failed to delete', 'Please try again'),
  loadFailed: () => toastError('Failed to load data', 'Please refresh the page'),
  networkError: () =>
    toastError('Network error', 'Please check your connection'),
  unauthorized: () =>
    toastError('Session expired', 'Please log in again'),
  validationError: (field?: string) =>
    toastError(
      'Validation error',
      field ? `Please check the ${field} field` : 'Please check your input'
    ),
};

