    34→      where: { id: userId },
    35→      select: userWithPlayerSelect,
    36→    });
    37→    if (!me) throw new NotFoundException('User not found');
    38→
    39→    // Audit log: profile viewed
    40→    await this.auditLog.log(userId, AuditAction.PROFILE_VIEWED, `Profile:${userId}`);
    41→
    42→    return me;
    43→  }
    44→
    45→  async updateMe(
    46→    userId: string,
    47→    dto: { firstName?: string; lastName?: string; ghinNumber?: string; handicap?: number | null },
    48→  ) {
    49→    // Normalize / sanitize inputs
    50→    const firstName = dto.firstName?.trim();
    51→    const lastName = dto.lastName?.trim();
    52→    const ghinNumberRaw = dto.ghinNumber?.trim();
    53→    const ghinNumber = ghinNumberRaw === '' ? null : ghinNumberRaw;
    54→
    55→    // If handicap comes as NaN or null, store null; otherwise use the number
    56→    const handicap =
    57→      dto.handicap === null || Number.isNaN(dto.handicap as number)
    58→        ? null
    59→        : dto.handicap;
    60→
    61→    // Ensure the user exists and perform updates atomically
    62→    return this.prisma.$transaction(async (tx) => {
    63→      const existing = await tx.user.findUnique({ where: { id: userId } });
    64→      if (!existing) throw new NotFoundException('User not found');
    65→
    66→      // Mirror name updates to User when provided
    67→      if (firstName !== undefined || lastName !== undefined) {
    68→        await tx.user.update({
    69→          where: { id: userId },
    70→          data: {
    71→            firstName: firstName ?? undefined,
    72→            lastName: lastName ?? undefined,
    73→          },
    74→        });
    75→      }
    76→
    77→      // Ensure a Player exists and update provided fields (no-op for undefined)
    78→      await tx.player.upsert({
    79→        where: { userId }, // userId is unique on Player
    80→        update: {
    81→          firstName: firstName ?? undefined,
    82→          lastName: lastName ?? undefined,
    83→          ghinNumber: ghinNumber ?? undefined, // can be string or null
    84→          handicap: handicap ?? undefined,      // can be number or null
    85→        },
    86→        create: {
    87→          userId,
    88→          firstName: firstName ?? existing.firstName ?? 'Golfer',
    89→          lastName: lastName ?? existing.lastName ?? 'User',
    90→          ghinNumber: ghinNumber ?? null,
    91→          handicap: handicap ?? null,
    92→        },
    93→      });
    94→
    95→      // Return the fresh shape
    96→      const updated = await tx.user.findUnique({
    97→        where: { id: userId },
    98→        select: userWithPlayerSelect,
    99→      });
   100→
   101→      // Narrow typing: updated cannot be null here, but keep a guard
   102→      if (!updated) throw new NotFoundException('User not found after update');
   103→
   104→      // Audit log: profile updated (track what changed)
   105→      const changedFields = Object.keys(dto).filter(key => dto[key as keyof typeof dto] !== undefined);
   106→      await this.auditLog.log(userId, AuditAction.PROFILE_UPDATED, `Profile:${userId}`, {
   107→        changedFields,
   108→        newValues: dto,
   109→      });
   110→
   111→      return updated;
   112→    });
   113→  }
   114→
   115→  /**
   116→   * Get user statistics (total rounds, average score, best/worst, etc.)
   117→   */
   118→  async getStats(userId: string) {
   119→    const player = await this.prisma.player.findUnique({
   120→      where: { userId },
   121→      include: {
   122→        rounds: {
   123→          where: { deletedAt: null },
   124→          orderBy: { date: 'desc' },
   125→          include: {
   126→            course: true, // Include related course data
   127→          },
   128→        },
   129→      },
   130→    });
   131→
   132→    if (!player) {
   133→      return {
   134→        totalRounds: 0,
   135→        averageScore: null,
   136→        bestScore: null,
   137→        worstScore: null,
   138→        bestRound: null,
   139→        worstRound: null,
   140→        recentRounds: [],
   141→        coursesPlayed: [],
   142→        scoreTrend: [],
   143→      };
   144→    }
   145→
   146→    const rounds = player.rounds;
   147→
   148→    if (rounds.length === 0) {
   149→      return {
   150→        totalRounds: 0,
   151→        averageScore: null,
   152→        bestScore: null,
   153→        worstScore: null,
   154→        bestRound: null,
   155→        worstRound: null,
   156→        recentRounds: [],
   157→        coursesPlayed: [],
   158→        scoreTrend: [],
   159→      };
   160→    }
   161→
   162→    const scores = rounds.map(r => r.strokes);
   163→    const totalRounds = rounds.length;
   164→    const averageScore = Math.round(scores.reduce((a, b) => a + b, 0) / totalRounds);
   165→    const bestScore = Math.min(...scores);
   166→    const worstScore = Math.max(...scores);
   167→
   168→    // Find best and worst round objects
   169→    const bestRound = rounds.find(r => r.strokes === bestScore);
   170→    const worstRound = rounds.find(r => r.strokes === worstScore);
   171→
   172→    // Format recent rounds with course information
   173→    const recentRounds = rounds.slice(0, 5).map(r => ({
   174→      id: r.id,
   175→      date: r.date,
   176→      strokes: r.strokes,
   177→      // Use course name from relation if available, otherwise fall back to courseName field
   178→      courseName: r.course?.name || r.courseName || 'Unknown Course',
   179→      notes: r.notes,
   180→    }));
   181→
   182→    // Get unique courses with count (prefer course relation, fall back to courseName)
   183→    const courseCounts = rounds.reduce((acc, r) => {
   184→      const name = r.course?.name || r.courseName;
   185→      if (name) {
   186→        acc[name] = (acc[name] || 0) + 1;
   187→      }
   188→      return acc;
   189→    }, {} as Record<string, number>);
   190→
   191→    const coursesPlayed = Object.entries(courseCounts)
   192→      .map(([name, count]) => ({ name, count }))
   193→      .sort((a, b) => b.count - a.count)
   194→      .slice(0, 5);
   195→
   196→    // Score trend for charting (sorted chronologically, oldest first)
   197→    const scoreTrend = [...rounds]
   198→      .sort((a, b) => a.date.getTime() - b.date.getTime())
   199→      .map(r => ({
   200→        date: r.date,
   201→        strokes: r.strokes,
   202→        courseName: r.course?.name || r.courseName || 'Unknown Course',
   203→      }));
   204→
   205→    return {
   206→      totalRounds,
   207→      averageScore,
   208→      bestScore,
   209→      worstScore,
   210→      bestRound: bestRound ? {
   211→        id: bestRound.id,
   212→        date: bestRound.date,
   213→        strokes: bestRound.strokes,
   214→        courseName: bestRound.course?.name || bestRound.courseName || 'Unknown Course',
   215→        notes: bestRound.notes,
   216→      } : null,
   217→      worstRound: worstRound ? {
   218→        id: worstRound.id,
   219→        date: worstRound.date,
   220→        strokes: worstRound.strokes,
   221→        courseName: worstRound.course?.name || worstRound.courseName || 'Unknown Course',
   222→        notes: worstRound.notes,
   223→      } : null,
   224→      recentRounds,
   225→      coursesPlayed,
   226→      scoreTrend,
   227→    };
   228→  }
   229→
   230→  /**
   231→   * Export all user data (GDPR compliance)
   232→   */
   233→  async exportUserData(userId: string) {
   234→    const user = await this.prisma.user.findUnique({
