import { Injectable, NotFoundException } from '@nestjs/common';
import { PrismaService } from '../prisma/prisma.service';
import { AuditLogService, AuditAction } from '../audit-log/audit-log.service';

const userWithPlayerSelect = {
  id: true,
  email: true,
  firstName: true,
  lastName: true,
  createdAt: true,
  updatedAt: true,
  // Hide provider/providerId from the API surface
  player: {
    select: {
      id: true,
      firstName: true,
      lastName: true,
      ghinNumber: true,
      handicap: true,
      createdAt: true,
    },
  },
} as const;

@Injectable()
export class ProfileService {
  constructor(
    private prisma: PrismaService,
    private auditLog: AuditLogService,
  ) {}

  async getMe(userId: string) {
    const me = await this.prisma.user.findUnique({
      where: { id: userId },
      select: userWithPlayerSelect,
    });
    if (!me) throw new NotFoundException('User not found');

    // Audit log: profile viewed
    await this.auditLog.log(userId, AuditAction.PROFILE_VIEWED, `Profile:${userId}`);

    return me;
  }

  async updateMe(
    userId: string,
    dto: { firstName?: string; lastName?: string; ghinNumber?: string; handicap?: number | null },
  ) {
    // Normalize / sanitize inputs
    const firstName = dto.firstName?.trim();
    const lastName = dto.lastName?.trim();
    const ghinNumberRaw = dto.ghinNumber?.trim();
    const ghinNumber = ghinNumberRaw === '' ? null : ghinNumberRaw;

    // If handicap comes as NaN or null, store null; otherwise use the number
    const handicap =
      dto.handicap === null || Number.isNaN(dto.handicap as number)
        ? null
        : dto.handicap;

    // Ensure the user exists and perform updates atomically
    return this.prisma.$transaction(async (tx) => {
      const existing = await tx.user.findUnique({ where: { id: userId } });
      if (!existing) throw new NotFoundException('User not found');

      // Mirror name updates to User when provided
      if (firstName !== undefined || lastName !== undefined) {
        await tx.user.update({
          where: { id: userId },
          data: {
            firstName: firstName ?? undefined,
            lastName: lastName ?? undefined,
          },
        });
      }

      // Ensure a Player exists and update provided fields (no-op for undefined)
      await tx.player.upsert({
        where: { userId }, // userId is unique on Player
        update: {
          firstName: firstName ?? undefined,
          lastName: lastName ?? undefined,
          ghinNumber: ghinNumber ?? undefined, // can be string or null
          handicap: handicap ?? undefined,      // can be number or null
        },
        create: {
          userId,
          firstName: firstName ?? existing.firstName ?? 'Golfer',
          lastName: lastName ?? existing.lastName ?? 'User',
          ghinNumber: ghinNumber ?? null,
          handicap: handicap ?? null,
        },
      });

      // Return the fresh shape
      const updated = await tx.user.findUnique({
        where: { id: userId },
        select: userWithPlayerSelect,
      });

      // Narrow typing: updated cannot be null here, but keep a guard
      if (!updated) throw new NotFoundException('User not found after update');

      // Audit log: profile updated (track what changed)
      const changedFields = Object.keys(dto).filter(key => dto[key as keyof typeof dto] !== undefined);
      await this.auditLog.log(userId, AuditAction.PROFILE_UPDATED, `Profile:${userId}`, {
        changedFields,
        newValues: dto,
      });

      return updated;
    });
  }

  /**
   * Get user statistics (total rounds, average score, best/worst, etc.)
   */
  async getStats(userId: string) {
    const player = await this.prisma.player.findUnique({
      where: { userId },
      include: {
        rounds: {
          where: { deletedAt: null },
          orderBy: { date: 'desc' },
          include: {
            course: true, // Include related course data
          },
        },
      },
    });

    if (!player) {
      return {
        totalRounds: 0,
        averageScore: null,
        bestScore: null,
        worstScore: null,
        bestRound: null,
        worstRound: null,
        recentRounds: [],
        coursesPlayed: [],
        scoreTrend: [],
      };
    }

    const rounds = player.rounds;

    if (rounds.length === 0) {
      return {
        totalRounds: 0,
        averageScore: null,
        bestScore: null,
        worstScore: null,
        bestRound: null,
        worstRound: null,
        recentRounds: [],
        coursesPlayed: [],
        scoreTrend: [],
      };
    }

    const scores = rounds.map(r => r.strokes);
    const totalRounds = rounds.length;
    const averageScore = Math.round(scores.reduce((a, b) => a + b, 0) / totalRounds);
    const bestScore = Math.min(...scores);
    const worstScore = Math.max(...scores);

    // Find best and worst round objects
    const bestRound = rounds.find(r => r.strokes === bestScore);
    const worstRound = rounds.find(r => r.strokes === worstScore);

    // Format recent rounds with course information
    const recentRounds = rounds.slice(0, 5).map(r => ({
      id: r.id,
      date: r.date,
      strokes: r.strokes,
      // Use course name from relation if available, otherwise fall back to courseName field
      courseName: r.course?.name || r.courseName || 'Unknown Course',
      notes: r.notes,
    }));

    // Get unique courses with count (prefer course relation, fall back to courseName)
    const courseCounts = rounds.reduce((acc, r) => {
      const name = r.course?.name || r.courseName;
      if (name) {
        acc[name] = (acc[name] || 0) + 1;
      }
      return acc;
    }, {} as Record<string, number>);

    const coursesPlayed = Object.entries(courseCounts)
      .map(([name, count]) => ({ name, count }))
      .sort((a, b) => b.count - a.count)
      .slice(0, 5);

    // Score trend for charting (sorted chronologically, oldest first)
    const scoreTrend = [...rounds]
      .sort((a, b) => a.date.getTime() - b.date.getTime())
      .map(r => ({
        date: r.date,
        strokes: r.strokes,
        courseName: r.course?.name || r.courseName || 'Unknown Course',
      }));

    return {
      totalRounds,
      averageScore,
      bestScore,
      worstScore,
      bestRound: bestRound ? {
        id: bestRound.id,
        date: bestRound.date,
        strokes: bestRound.strokes,
        courseName: bestRound.course?.name || bestRound.courseName || 'Unknown Course',
        notes: bestRound.notes,
      } : null,
      worstRound: worstRound ? {
        id: worstRound.id,
        date: worstRound.date,
        strokes: worstRound.strokes,
        courseName: worstRound.course?.name || worstRound.courseName || 'Unknown Course',
        notes: worstRound.notes,
      } : null,
      recentRounds,
      coursesPlayed,
      scoreTrend,
    };
  }

  /**
   * Export all user data (GDPR compliance)
   */
  async exportUserData(userId: string) {
    const user = await this.prisma.user.findUnique({
      where: { id: userId },
      include: {
        player: {
          include: {
            rounds: {
              where: { deletedAt: null }, // Only include active rounds
              orderBy: { date: 'desc' },
            },
          },
        },
      },
    });

    if (!user) throw new NotFoundException('User not found');

    // Audit log: data export
    await this.auditLog.log(userId, AuditAction.DATA_EXPORTED, `User:${userId}`);

    return {
      user: {
        id: user.id,
        email: user.email,
        firstName: user.firstName,
        lastName: user.lastName,
        avatarUrl: user.avatarUrl,
        locale: user.locale,
        emailVerified: user.emailVerified,
        lastLoginAt: user.lastLoginAt,
        createdAt: user.createdAt,
        updatedAt: user.updatedAt,
      },
      player: user.player ? {
        id: user.player.id,
        firstName: user.player.firstName,
        lastName: user.player.lastName,
        ghinNumber: user.player.ghinNumber,
        handicap: user.player.handicap,
        createdAt: user.player.createdAt,
      } : null,
      rounds: user.player?.rounds || [],
      exportedAt: new Date().toISOString(),
    };
  }

  /**
   * Delete user account and all associated data (GDPR right to be forgotten)
   */
  async deleteUserAccount(userId: string) {
    const user = await this.prisma.user.findUnique({
      where: { id: userId },
      include: { player: true },
    });

    if (!user) throw new NotFoundException('User not found');

    // Audit log: account deletion (before deleting)
    await this.auditLog.log(userId, AuditAction.ACCOUNT_DELETED, `User:${userId}`, {
      email: user.email,
      deletedAt: new Date().toISOString(),
    });

    // Delete in transaction (cascade will handle rounds and audit logs)
    await this.prisma.$transaction(async (tx) => {
      // Delete player (will cascade to rounds if configured)
      if (user.player) {
        await tx.round.deleteMany({
          where: { playerId: user.player.id },
        });
        await tx.player.delete({
          where: { id: user.player.id },
        });
      }

      // Delete audit logs for this user
      await tx.auditLog.deleteMany({
        where: { userId },
      });

      // Finally, delete the user
      await tx.user.delete({
        where: { id: userId },
      });
    });

    return { deleted: true, userId };
  }
}

