    totalBirdies: rounds.reduce((sum, r) => sum + (r.birdies || 0), 0),
    totalPars: rounds.reduce((sum, r) => sum + (r.pars || 0), 0),
    totalBogeys: rounds.reduce((sum, r) => sum + (r.bogeys || 0), 0),
    totalDoubleBogeys: rounds.reduce((sum, r) => sum + (r.doubleBogeys || 0), 0),
    totalTriplePlusBogeys: rounds.reduce((sum, r) => sum + (r.triplePlusBogeys || 0), 0),

    // Rounds with data counts (for UI display)
    roundsWithGirData: roundsWithGir.length,
    roundsWithFirData: roundsWithFir.length,
    roundsWithPuttsData: roundsWithPutts.length,
  };

  // Scoring distribution for chart (percentage breakdown)
  const totalScoringHoles = advancedStats.totalHoleInOnes + advancedStats.totalEagles +
    advancedStats.totalBirdies + advancedStats.totalPars + advancedStats.totalBogeys +
    advancedStats.totalDoubleBogeys + advancedStats.totalTriplePlusBogeys;

  const scoringDistribution = totalScoringHoles > 0 ? {
    holeInOnes: { count: advancedStats.totalHoleInOnes, pct: Math.round(advancedStats.totalHoleInOnes / totalScoringHoles * 100) },
    eagles: { count: advancedStats.totalEagles, pct: Math.round(advancedStats.totalEagles / totalScoringHoles * 100) },
    birdies: { count: advancedStats.totalBirdies, pct: Math.round(advancedStats.totalBirdies / totalScoringHoles * 100) },
    pars: { count: advancedStats.totalPars, pct: Math.round(advancedStats.totalPars / totalScoringHoles * 100) },
    bogeys: { count: advancedStats.totalBogeys, pct: Math.round(advancedStats.totalBogeys / totalScoringHoles * 100) },
    doubleBogeys: { count: advancedStats.totalDoubleBogeys, pct: Math.round(advancedStats.totalDoubleBogeys / totalScoringHoles * 100) },
    triplePlusBogeys: { count: advancedStats.totalTriplePlusBogeys, pct: Math.round(advancedStats.totalTriplePlusBogeys / totalScoringHoles * 100) },
  } : null;

  return {
    totalRounds,
    averageScore,
    bestScore,
    worstScore,
    bestRound: bestRound ? {
      id: bestRound.id,
      date: bestRound.date,
      strokes: bestRound.strokes,
      courseName: bestRound.course?.name || bestRound.courseName || 'Unknown Course',
      notes: bestRound.notes,
    } : null,
    worstRound: worstRound ? {
      id: worstRound.id,
      date: worstRound.date,
      strokes: worstRound.strokes,
      courseName: worstRound.course?.name || worstRound.courseName || 'Unknown Course',
      notes: worstRound.notes,
    } : null,
    recentRounds,
    coursesPlayed,
    scoreTrend,
    advancedStats,
    scoringDistribution,
  };
}

