'use client';

import { useEffect, useState } from 'react';
import { apiRequest } from '@/lib/api';
import { toast } from '@/lib/toast';
import { PageLoader, StatsSkeleton } from '@/components/loading';
import type { UserStats } from '@/types/stats';
import { cn } from '@/lib/utils';

export default function StatsPage() {
  const [stats, setStats] = useState<UserStats | null>(null);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    async function fetchStats() {
      const { ok, data, status } = await apiRequest<UserStats>('/v1/me/stats');

      if (!ok) {
        if (status === 401) {
          toast.unauthorized();
          window.location.href = '/login';
          return;
        }
        toast.loadFailed();
        setLoading(false);
        return;
      }

      setStats(data);
      setLoading(false);
    }

    fetchStats();
  }, []);

  if (loading) {
    return (
      <div className="w-full max-w-[1800px] mx-auto px-4 sm:px-6 lg:px-8 py-8">
        <div className="space-y-6">
          <div className="space-y-2">
            <div className="h-8 w-48 bg-muted rounded animate-pulse" />
            <div className="h-4 w-64 bg-muted rounded animate-pulse" />
          </div>
          <div className="grid grid-cols-2 md:grid-cols-4 gap-4">
            <StatsSkeleton />
            <StatsSkeleton />
            <StatsSkeleton />
            <StatsSkeleton />
          </div>
        </div>
      </div>
    );
  }

  if (!stats) {
    return (
      <div className="w-full max-w-[1800px] mx-auto px-4 sm:px-6 lg:px-8 py-8">
        <div className="glass rounded-xl p-8 text-center">
          <h2 className="text-xl font-semibold mb-2">Unable to load statistics</h2>
          <p className="text-muted-foreground">Please try refreshing the page.</p>
        </div>
      </div>
    );
  }

  const hasNoRounds = stats.totalRounds === 0;

  return (
    <div className="w-full max-w-[1800px] mx-auto px-4 sm:px-6 lg:px-8 py-8 space-y-8">
      {/* Header */}
      <div className="space-y-2">
        <h1 className="text-3xl font-bold">
          Your Golf <span className="gradient-text">Statistics</span>
        </h1>
        <p className="text-muted-foreground">
          Track your progress and analyze your game
        </p>
      </div>

      {hasNoRounds ? (
        <EmptyStats />
      ) : (
        <>
          {/* Key Stats Grid */}
          <div className="grid grid-cols-2 md:grid-cols-4 gap-4">
            <StatCard
              label="Total Rounds"
              value={stats.totalRounds}
              icon="🏌️"
            />
            <StatCard
              label="Average Score"
              value={stats.averageScore ?? '-'}
              icon="📊"
            />
            <StatCard
              label="Best Score"
              value={stats.bestScore ?? '-'}
              icon="🏆"
              variant="success"
            />
            <StatCard
              label="Worst Score"
              value={stats.worstScore ?? '-'}
              icon="📉"
              variant="warning"
            />
          </div>

          {/* Advanced Stats */}
          {stats.advancedStats && (
            <AdvancedStatsSection stats={stats.advancedStats} totalRounds={stats.totalRounds} />
          )}

          {/* Scoring Distribution */}
          {stats.scoringDistribution && (
            <ScoringDistributionSection distribution={stats.scoringDistribution} />
          )}

          {/* Score Trend Chart (simplified) */}
          {stats.scoreTrend.length > 1 && (
            <ScoreTrendSection trend={stats.scoreTrend} />
          )}

          {/* Recent Rounds & Courses */}
          <div className="grid md:grid-cols-2 gap-6">
            <RecentRoundsSection rounds={stats.recentRounds} />
            <TopCoursesSection courses={stats.coursesPlayed} />
          </div>
        </>
      )}
    </div>
  );
}

// =============================================================================
// Sub-components
// =============================================================================

function EmptyStats() {
  return (
    <div className="glass rounded-xl p-12 text-center">
      <div className="text-6xl mb-4">⛳</div>
      <h2 className="text-2xl font-semibold mb-2">No Rounds Yet</h2>
      <p className="text-muted-foreground mb-6 max-w-md mx-auto">
        Start tracking your rounds to see your statistics, trends, and progress over time.
      </p>
      <a
        href="/rounds/new"
        className="inline-flex items-center gap-2 px-6 py-3 bg-primary text-primary-foreground rounded-lg font-medium hover:bg-primary/90 transition-colors"
      >
        Log Your First Round
      </a>
    </div>
  );
}

function StatCard({
  label,
  value,
  icon,
  variant = 'default',
}: {
  label: string;
  value: string | number;
  icon: string;
  variant?: 'default' | 'success' | 'warning';
}) {
  const variantClasses = {
    default: '',
    success: 'border-brand-cyan/30',
    warning: 'border-brand-orange/30',
  };

  return (
    <div className={cn('glass rounded-xl p-6', variantClasses[variant])}>
      <div className="flex items-center gap-3 mb-2">
        <span className="text-2xl">{icon}</span>
        <span className="text-sm text-muted-foreground">{label}</span>
      </div>
      <div className="text-3xl font-bold">{value}</div>
    </div>
  );
}

function AdvancedStatsSection({
  stats,
  totalRounds,
}: {
  stats: NonNullable<UserStats['advancedStats']>;
  totalRounds: number;
}) {
  const hasAnyData =
    stats.averageGir !== null ||
    stats.averageFir !== null ||
    stats.averagePutts !== null;

  if (!hasAnyData) return null;

  return (
    <div className="space-y-4">
      <h2 className="text-xl font-semibold">Performance Metrics</h2>
      <div className="grid grid-cols-1 sm:grid-cols-3 gap-4">
        <PerformanceCard
          label="Greens in Regulation"
          value={stats.averageGir}
          suffix="%"
          dataRounds={stats.roundsWithGirData}
          totalRounds={totalRounds}
          goodThreshold={50}
        />
        <PerformanceCard
          label="Fairways in Regulation"
          value={stats.averageFir}
          suffix="%"
          dataRounds={stats.roundsWithFirData}
          totalRounds={totalRounds}
          goodThreshold={50}
        />
        <PerformanceCard
          label="Average Putts"
          value={stats.averagePutts}
          suffix=" per round"
          dataRounds={stats.roundsWithPuttsData}
          totalRounds={totalRounds}
          goodThreshold={32}
          lowerIsBetter
        />
      </div>
    </div>
  );
}

function PerformanceCard({
  label,
  value,
  suffix,
  dataRounds,
  totalRounds,
  goodThreshold,
  lowerIsBetter = false,
}: {
  label: string;
  value: number | null;
  suffix: string;
  dataRounds: number;
  totalRounds: number;
  goodThreshold: number;
  lowerIsBetter?: boolean;
}) {
  if (value === null) {
    return (
      <div className="glass rounded-xl p-6 opacity-60">
        <div className="text-sm text-muted-foreground mb-1">{label}</div>
        <div className="text-2xl font-bold text-muted-foreground">-</div>
        <div className="text-xs text-muted-foreground mt-2">No data yet</div>
      </div>
    );
  }

  const isGood = lowerIsBetter ? value <= goodThreshold : value >= goodThreshold;

  return (
    <div className="glass rounded-xl p-6">
      <div className="text-sm text-muted-foreground mb-1">{label}</div>
      <div className={cn('text-2xl font-bold', isGood ? 'text-brand-cyan' : 'text-brand-orange')}>
        {value}{suffix}
      </div>
      <div className="text-xs text-muted-foreground mt-2">
        Based on {dataRounds} of {totalRounds} rounds
      </div>
    </div>
  );
}

function ScoringDistributionSection({
  distribution,
}: {
  distribution: NonNullable<UserStats['scoringDistribution']>;
}) {
  const categories = [
    { key: 'holeInOnes', label: 'Hole-in-Ones', color: 'bg-brand-pink', data: distribution.holeInOnes },
    { key: 'eagles', label: 'Eagles', color: 'bg-brand-purple', data: distribution.eagles },
    { key: 'birdies', label: 'Birdies', color: 'bg-brand-cyan', data: distribution.birdies },
    { key: 'pars', label: 'Pars', color: 'bg-brand-green', data: distribution.pars },
    { key: 'bogeys', label: 'Bogeys', color: 'bg-brand-orange', data: distribution.bogeys },
    { key: 'doubleBogeys', label: 'Double Bogeys', color: 'bg-brand-coral', data: distribution.doubleBogeys },
    { key: 'triplePlusBogeys', label: 'Triple+', color: 'bg-destructive', data: distribution.triplePlusBogeys },
  ].filter(c => c.data.count > 0);

  if (categories.length === 0) return null;

  return (
    <div className="space-y-4">
      <h2 className="text-xl font-semibold">Scoring Distribution</h2>
      <div className="glass rounded-xl p-6">
        {/* Bar chart */}
        <div className="flex gap-1 h-8 mb-4 rounded overflow-hidden">
          {categories.map((cat) => (
            <div
              key={cat.key}
              className={cn('transition-all', cat.color)}
              style={{ width: `${cat.data.pct}%` }}
              title={`${cat.label}: ${cat.data.count} (${cat.data.pct}%)`}
            />
          ))}
        </div>

        {/* Legend */}
        <div className="flex flex-wrap gap-4">
          {categories.map((cat) => (
            <div key={cat.key} className="flex items-center gap-2">
              <div className={cn('w-3 h-3 rounded', cat.color)} />
              <span className="text-sm">
                {cat.label}: <span className="font-semibold">{cat.data.count}</span>
              </span>
            </div>
          ))}
        </div>
      </div>
    </div>
  );
}

function ScoreTrendSection({ trend }: { trend: UserStats['scoreTrend'] }) {
  const scores = trend.map((t) => t.strokes);
  const min = Math.min(...scores);
  const max = Math.max(...scores);
  const range = max - min || 1;

  // Simple SVG line chart
  const width = 100;
  const height = 40;
  const padding = 2;

  const points = trend.map((t, i) => {
    const x = (i / (trend.length - 1)) * (width - padding * 2) + padding;
    const y = height - padding - ((t.strokes - min) / range) * (height - padding * 2);
    return `${x},${y}`;
  }).join(' ');

  return (
    <div className="space-y-4">
      <h2 className="text-xl font-semibold">Score Trend</h2>
      <div className="glass rounded-xl p-6">
        <svg viewBox={`0 0 ${width} ${height}`} className="w-full h-32">
          {/* Grid lines */}
          <line x1="0" y1={height / 2} x2={width} y2={height / 2} stroke="currentColor" strokeOpacity="0.1" />

          {/* Trend line */}
          <polyline
            points={points}
            fill="none"
            stroke="url(#gradient)"
            strokeWidth="2"
            strokeLinecap="round"
            strokeLinejoin="round"
          />

          {/* Gradient definition */}
          <defs>
            <linearGradient id="gradient" x1="0%" y1="0%" x2="100%" y2="0%">
              <stop offset="0%" stopColor="#ff0080" />
              <stop offset="100%" stopColor="#00f0ff" />
            </linearGradient>
          </defs>
        </svg>

        <div className="flex justify-between text-sm text-muted-foreground mt-2">
          <span>{new Date(trend[0].date).toLocaleDateString()}</span>
          <span className="text-center">
            {trend.length} rounds • Range: {min} - {max}
          </span>
          <span>{new Date(trend[trend.length - 1].date).toLocaleDateString()}</span>
        </div>
      </div>
    </div>
  );
}

function RecentRoundsSection({ rounds }: { rounds: UserStats['recentRounds'] }) {
  if (rounds.length === 0) return null;

  return (
    <div className="space-y-4">
      <h2 className="text-xl font-semibold">Recent Rounds</h2>
      <div className="glass rounded-xl divide-y divide-border/50">
        {rounds.map((round) => (
          <div key={round.id} className="p-4 flex justify-between items-center">
            <div>
              <div className="font-medium">{round.courseName}</div>
              <div className="text-sm text-muted-foreground">
                {new Date(round.date).toLocaleDateString()}
              </div>
            </div>
            <div className="text-2xl font-bold">{round.strokes}</div>
          </div>
        ))}
      </div>
    </div>
  );
}

function TopCoursesSection({ courses }: { courses: UserStats['coursesPlayed'] }) {
  if (courses.length === 0) return null;

  return (
    <div className="space-y-4">
      <h2 className="text-xl font-semibold">Most Played Courses</h2>
