          // Neon colors (primary in dark mode)
          pink: '#ff0080',
          'pink-dark': '#cc0066',
          'pink-light': '#ff3399',
          cyan: '#00f0ff',
          'cyan-dark': '#00c0cc',
          'cyan-light': '#33f5ff',
          purple: '#9b59ff',
