          '0%, 100%': {
            boxShadow: '0 0 20px hsl(var(--brand-primary) / 0.3)',
          },
          '50%': {
            boxShadow: '0 0 40px hsl(var(--brand-primary) / 0.6)',
          },
        },
        shimmer: {
          '0%': { backgroundPosition: '-200% 0' },
          '100%': { backgroundPosition: '200% 0' },
        },
      },
      animation: {
        'fade-in': 'fade-in 0.3s ease-out',
        'fade-up': 'fade-up 0.4s ease-out',
        'slide-in-right': 'slide-in-right 0.3s ease-out',
        'pulse-glow': 'pulse-glow 2s ease-in-out infinite',
        shimmer: 'shimmer 2s linear infinite',
      },
      backgroundImage: {
        // Neon gradients (dark mode favorites)
        'gradient-miami': 'linear-gradient(135deg, #ff0080 0%, #00f0ff 100%)',
        'gradient-neon': 'linear-gradient(135deg, #00f0ff 0%, #ff0080 50%, #9b59ff 100%)',
        // Sunset gradients (light mode favorites)
        'gradient-sunset': 'linear-gradient(135deg, #ff7033 0%, #ff6b6b 50%, #ff0080 100%)',
        'gradient-golden': 'linear-gradient(135deg, #ffbf00 0%, #ff7033 100%)',
        // Universal
        'gradient-rainbow': 'linear-gradient(135deg, #ff0080, #ff7033, #ffbf00, #00f0ff, #9b59ff)',
      },
    },
  },
  plugins: [],
};

export default config;

